-- Generated by scripts/scrape_spectrum_speedball_chrysanthos.py from official Spectrum, Speedball, and Chrysanthos sources on 2026-04-04.
delete from public.glaze_firing_images
where glaze_id in (
  select id
  from public.glazes
  where brand in ('Spectrum', 'Speedball', 'Chrysanthos')
    and created_by_user_id is null
);

insert into public.glaze_firing_images (
  glaze_id,
  label,
  cone,
  atmosphere,
  image_url,
  sort_order
)
